"""
Secure Elasticsearch aggregation client with predefined script templates.
NEVER execute arbitrary user-supplied scripts directly.
"""

from elasticsearch import Elasticsearch
from typing import Any, Optional
import re


# Whitelist of allowed, pre-defined aggregation operations
ALLOWED_SCRIPTS = {
    "weighted_average": {
        "id": "weighted_avg_script",
        "source": "doc[params.value_field].value * doc[params.weight_field].value",
        "lang": "painless",
        "description": "Calculates weighted value for aggregation",
        "required_params": ["value_field", "weight_field"],
    },
    "percentage_of_total": {
        "id": "pct_of_total_script",
        "source": "(doc[params.value_field].value / params.total) * 100",
        "lang": "painless",
        "description": "Calculates percentage of a given total",
        "required_params": ["value_field", "total"],
    },
    "date_diff_days": {
        "id": "date_diff_days_script",
        "source": "(doc[params.end_field].value.toInstant().toEpochMilli() - doc[params.start_field].value.toInstant().toEpochMilli()) / 86400000L",
        "lang": "painless",
        "description": "Calculates difference in days between two date fields",
        "required_params": ["start_field", "end_field"],
    },
    "conditional_sum": {
        "id": "conditional_sum_script",
        "source": "doc[params.value_field].value > params.threshold ? doc[params.value_field].value : 0",
        "lang": "painless",
        "description": "Sums values only if they exceed a threshold",
        "required_params": ["value_field", "threshold"],
    },
    "normalized_score": {
        "id": "normalized_score_script",
        "source": "(doc[params.value_field].value - params.min_val) / (params.max_val - params.min_val)",
        "lang": "painless",
        "description": "Min-max normalization of a field",
        "required_params": ["value_field", "min_val", "max_val"],
    },
}

# Regex to validate field names - only allow alphanumeric and underscores
VALID_FIELD_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_.]*$")


class SecureElasticsearchAggregator:
    """
    Elasticsearch aggregation client that uses ONLY pre-defined,
    parameterized scripts. Does NOT accept arbitrary script code.
    """

    def __init__(
        self,
        hosts: list[str],
        api_key: Optional[tuple[str, str]] = None,
        ca_certs: Optional[str] = None,
        verify_certs: bool = True,
    ):
        connection_params = {
            "hosts": hosts,
            "verify_certs": verify_certs,
            "request_timeout": 30,
            "max_retries": 3,
        }

        if api_key:
            connection_params["api_key"] = api_key
        if ca_certs:
            connection_params["ca_certs"] = ca_certs

        self.client = Elasticsearch(**connection_params)
        self._verify_connection()

    def _verify_connection(self) -> None:
        """Verify Elasticsearch cluster is reachable."""
        if not self.client.ping():
            raise ConnectionError("Cannot connect to Elasticsearch cluster")
        info = self.client.info()
        print(f"Connected to Elasticsearch {info['version']['number']}")

    def list_available_scripts(self) -> dict[str, str]:
        """Return descriptions of all available aggregation scripts."""
        return {
            name: details["description"]
            for name, details in ALLOWED_SCRIPTS.items()
        }

    def _validate_field_name(self, field_name: str) -> str:
        """
        Validate that a field name is safe to use in scripts.
        Prevents injection through field name parameters.
        """
        if not isinstance(field_name, str):
            raise ValueError(f"Field name must be a string, got {type(field_name)}")
        if not VALID_FIELD_PATTERN.match(field_name):
            raise ValueError(
                f"Invalid field name '{field_name}'. "
                "Only alphanumeric characters, underscores, and dots are allowed."
            )
        if len(field_name) > 256:
            raise ValueError("Field name too long (max 256 characters)")
        return field_name

    def _validate_numeric_param(self, value: Any, param_name: str) -> float:
        """Validate and sanitize numeric parameters."""
        try:
            result = float(value)
        except (TypeError, ValueError):
            raise ValueError(
                f"Parameter '{param_name}' must be numeric, got {type(value).__name__}"
            )

        if not (-1e15 <= result <= 1e15):
            raise ValueError(
                f"Parameter '{param_name}' value {result} is out of acceptable range"
            )
        return result

    def _validate_params(
        self, script_name: str, params: dict[str, Any]
    ) -> dict[str, Any]:
        """
        Validate all parameters for a given script.
        Ensures required params are present and values are safe.
        """
        script_def = ALLOWED_SCRIPTS[script_name]
        required = script_def["required_params"]

        missing = set(required) - set(params.keys())
        if missing:
            raise ValueError(
                f"Missing required parameters for '{script_name}': {missing}"
            )

        # Only allow expected parameters - reject extras
        allowed_param_names = set(required)
        extra = set(params.keys()) - allowed_param_names
        if extra:
            raise ValueError(
                f"Unexpected parameters for '{script_name}': {extra}. "
                f"Allowed: {allowed_param_names}"
            )

        validated = {}
        for param_name, value in params.items():
            if param_name.endswith("_field"):
                validated[param_name] = self._validate_field_name(value)
            else:
                validated[param_name] = self._validate_numeric_param(value, param_name)

        return validated

    def register_stored_scripts(self) -> None:
        """
        Register all allowed scripts as stored scripts in Elasticsearch.
        This is the secure approach - scripts are stored server-side,
        not passed inline from user input.
        """
        for name, script_def in ALLOWED_SCRIPTS.items():
            try:
                self.client.put_script(
                    id=script_def["id"],
                    body={
                        "script": {
                            "lang": script_def["lang"],
                            "source": script_def["source"],
                        }
                    },
                )
                print(f"Registered stored script: {script_def['id']}")
            except Exception as e:
                print(f"Warning: Could not register script '{name}': {e}")

    def execute_aggregation(
        self,
        index: str,
        script_name: str,
        params: dict[str, Any],
        agg_type: str = "sum",
        query: Optional[dict] = None,
        size: int = 0,
    ) -> dict:
        """
        Execute an aggregation using a pre-defined, whitelisted script.

        Args:
            index: Elasticsearch index name
            script_name: Name of the pre-defined script (from ALLOWED_SCRIPTS)
            params: Parameters for the script (field names, thresholds, etc.)
            agg_type: Aggregation type ('sum', 'avg', 'min', 'max', 'stats',
                      'value_count')
            query: Optional Elasticsearch query to filter documents
            size: Number of hits to return (0 for aggregation-only)

        Returns:
            Aggregation results dictionary
        """
        # Step 1: Validate script_name is in the whitelist
        if script_name not in ALLOWED_SCRIPTS:
            raise ValueError(
                f"Unknown script '{script_name}'. "
                f"Available scripts: {list(ALLOWED_SCRIPTS.keys())}"
            )

        # Step 2: Validate index name
        self._validate_field_name(index)

        # Step 3: Validate aggregation type
        allowed_agg_types = {"sum", "avg", "min", "max", "stats", "value_count"}
        if agg_type not in allowed_agg_types:
            raise ValueError(
                f"Invalid aggregation type '{agg_type}'. "
                f"Allowed: {allowed_agg_types}"
            )

        # Step 4: Validate and sanitize all parameters
        validated_params = self._validate_params(script_name, params)

        # Step 5: Build the aggregation using the stored script ID
        script_def = ALLOWED_SCRIPTS[script_name]

        agg_body = {
            "scripted_agg": {
                agg_type: {
                    "script": {
                        "id": script_def["id"],
                        "params": validated_params,
                    }
                }
            }
        }

        search_body = {
            "size": min(max(size, 0), 100),  # Cap at 100 results
            "aggs": agg_body,
        }

        if query:
            search_body["query"] = query

        result = self.client.search(index=index, body=search_body)

        return {
            "total_hits": result["hits"]["total"]["value"]
            if isinstance(result["hits"]["total"], dict)
            else result["hits"]["total"],
            "aggregation": result["aggregations"]["scripted_agg"],
            "script_used": script_name,
            "parameters": validated_params,
        }

    def execute_bucket_script_aggregation(
        self,
        index: str,
        script_name: str,
        params: dict[str, Any],
        bucket_field: str,
        bucket_size: int = 10,
        metric_field: Optional[str] = None,
        query: Optional[dict] = None,
    ) -> dict:
        """
        Execute a bucket aggregation with a scripted metric.

        Args:
            index: Elasticsearch index name
            script_name: Pre-defined script name
            params: Script parameters
            bucket_field: Field to create buckets on
            bucket_size: Number of buckets to return
            metric_field: Field for sub-metric aggregation
            query: Optional filter query

        Returns:
            Bucket aggregation results
        """
        if script_name not in ALLOWED_SCRIPTS:
            raise ValueError(
                f"Unknown script '{script_name}'. "
                f"Available: {list(ALLOWED_SCRIPTS.keys())}"
            )

        self._validate_field_name(index)
        self._validate_field_name(bucket_field)
        validated_params = self._validate_params(script_name, params)
        bucket_size = min(max(bucket_size, 1), 100)

        script_def = ALLOWED_SCRIPTS[script_name]

        agg_body = {
            "buckets": {
                "terms": {
                    "field": bucket_field,
                    "size": bucket_size,
                },
                "aggs": {
                    "scripted_metric": {
                        "avg": {
                            "script": {
                                "id": script_def["id"],
                                "params": validated_params,
                            }
                        }
                    }
                },
            }
        }

        if metric_field:
            self._validate_field_name(metric_field)
            agg_body["buckets"]["aggs"]["field_metric"] = {
                "avg": {"field": metric_field}
            }

        search_body = {
            "size": 0,
            "aggs": agg_body,
        }

        if query:
            search_body["query"] = query

        result = self.client.search(index=index, body=search_body)

        return {
            "total_hits": result["hits"]["total"]["value"]
            if isinstance(result["hits"]["total"], dict)
            else result["hits"]["total"],
            "buckets": result["aggregations"]["buckets"]["buckets"],
            "script_used": script_name,
            "parameters": validated_params,
        }


